import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1777706209000}'),i={name:"faq.md"};function d(n,a,h,l,s,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="没装过-git-能用吗" tabindex="-1">没装过 Git 能用吗？ <a class="header-anchor" href="#没装过-git-能用吗" aria-label="Permalink to &quot;没装过 Git 能用吗？&quot;">​</a></h2><p>能。软件会自动下载所需的 Git 组件，无需手动安装。</p><h2 id="会影响游戏本体文件吗" tabindex="-1">会影响游戏本体文件吗？ <a class="header-anchor" href="#会影响游戏本体文件吗" aria-label="Permalink to &quot;会影响游戏本体文件吗？&quot;">​</a></h2><p>不会。软件只操作 Mods 文件夹和存档文件夹，不修改游戏本体。关闭 Mod 开关即可恢复原版状态。</p><h2 id="我的账号密码安全吗" tabindex="-1">我的账号密码安全吗？ <a class="header-anchor" href="#我的账号密码安全吗" aria-label="Permalink to &quot;我的账号密码安全吗？&quot;">​</a></h2><p>认证信息使用 Windows 系统级加密（DPAPI）存储，不上传到任何服务器，仅本机当前用户可读取。</p><h2 id="支持哪些-git-平台" tabindex="-1">支持哪些 Git 平台？ <a class="header-anchor" href="#支持哪些-git-平台" aria-label="Permalink to &quot;支持哪些 Git 平台？&quot;">​</a></h2><p>支持 Gitee、GitHub、GitLab 等主流平台。Gitee 推荐使用「免密」方式，GitHub 推荐使用「HTTPS + Token」方式。详见<a href="/guide/getting-started">快速上手</a>。</p><h2 id="支持哪些游戏" tabindex="-1">支持哪些游戏？ <a class="header-anchor" href="#支持哪些游戏" aria-label="Permalink to &quot;支持哪些游戏？&quot;">​</a></h2><p>目前完整支持<strong>杀戮尖塔 2</strong>。<strong>星露谷物语</strong>和 <strong>Minecraft</strong> 的支持正在开发中。你也可以选择「通用」类型来做基础的 Git 文件夹同步。</p><h2 id="可以同时管理多个游戏吗" tabindex="-1">可以同时管理多个游戏吗？ <a class="header-anchor" href="#可以同时管理多个游戏吗" aria-label="Permalink to &quot;可以同时管理多个游戏吗？&quot;">​</a></h2><p>可以。v2.0 新增了<a href="/guide/workspace">多工作区</a>功能，你可以为每个游戏创建独立的工作区，互不干扰。</p><h2 id="界面语言可以切换吗" tabindex="-1">界面语言可以切换吗？ <a class="header-anchor" href="#界面语言可以切换吗" aria-label="Permalink to &quot;界面语言可以切换吗？&quot;">​</a></h2><p>可以。点击仪表盘右上角的设置按钮，在设置面板中选择「语言」即可切换。目前支持中文和英文。</p><h2 id="上传-拉取时进度条卡住怎么办" tabindex="-1">上传/拉取时进度条卡住怎么办？ <a class="header-anchor" href="#上传-拉取时进度条卡住怎么办" aria-label="Permalink to &quot;上传/拉取时进度条卡住怎么办？&quot;">​</a></h2><p>克隆或拉取操作取决于仓库大小和网络速度，较大的仓库首次同步可能需要较长时间。如果进度条长时间没有变化（超过 2 分钟），可以尝试关闭软件后重新打开。</p><h2 id="mod-差异预览显示什么" tabindex="-1">Mod 差异预览显示什么？ <a class="header-anchor" href="#mod-差异预览显示什么" aria-label="Permalink to &quot;Mod 差异预览显示什么？&quot;">​</a></h2><p>在上传或拉取 Mod 前，软件会自动比较本地和远程的 Mod 差异，显示新增、更新、移除的 Mod 列表，让你在确认后才执行操作。详见 <a href="/guide/mod-manager#mod-差异比较">Mod 管理</a>。</p>',19)])])}const f=e(i,[["render",d]]);export{u as __pageData,f as default};
